export default function Toolbar({
  onNew,
  onSave,
  onLoad,
  isSidebarCollapsed,
  isPropertiesCollapsed,
  onToggleSidebar,
  onToggleProperties,
}) {
  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';

  const [toolMenuOpen, setToolMenuOpen] = useState(false);
  const toolMenuRef = useRef(null);
  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });

  const toolItems = [
    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V' },
    { tool: TOOLS.DIMENSION, label: 'Dim', shortcut: 'M' },
    { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W' },
    { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B' },
    { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T' },
    { tool: TOOLS.SECTION, label: 'Section', shortcut: 'Q' },
    { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S' },
    { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R' },
    { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D' },
    { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N' },
    { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C' },
  ];
  const activeToolLabel = toolItems.find(t => t.tool === activeTool)?.label || 'Tools';
  const handleUndo = useCallback(() => {
    if (!canUndo) return;
    dispatch({ type: 'UNDO' });
    editorDispatch({ type: 'DESELECT' });
    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
  }, [canUndo, dispatch, editorDispatch]);
  const handleRedo = useCallback(() => {
    if (!canRedo) return;
    dispatch({ type: 'REDO' });
    editorDispatch({ type: 'DESELECT' });
    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
  }, [canRedo, dispatch, editorDispatch]);

  const handleDetectRooms = () => {
    const floor = project.floors.find(f => f.id === activeFloorId);
    if (!floor || floor.walls.length < 3) {
      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
      return;
    }

    const detected = detectRooms(floor.walls, floor.columns || []);
    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
    editorDispatch({ type: 'DESELECT' });
    editorDispatch({
      type: 'SET_STATUS_MESSAGE',
      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
    });
  };

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (!(e.ctrlKey || e.metaKey)) return;
      if (isTypingTarget(e.target)) return;

      const key = e.key.toLowerCase();
      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
      const isUndo = key === 'z' && !e.shiftKey;
      if (!isUndo && !isRedo) return;

      e.preventDefault();
      if (isRedo) {
        handleRedo();
        return;
      }
      handleUndo();
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleRedo, handleUndo]);

  useEffect(() => {
    if (!toolMenuOpen) return;
    const handleClickOutside = (e) => {
      if (toolMenuRef.current && !toolMenuRef.current.contains(e.target)) {
        setToolMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [toolMenuOpen]);

  return (
    <div className={styles.toolbar}>
      <div className={styles.group}>
        <button className={styles.btn} onClick={onNew}>New</button>
        <button
          className={`${styles.btn} ${styles.iconBtn}`}
          onClick={handleUndo}
          disabled={!canUndo}
          title="Undo (Ctrl/Cmd+Z)"
          aria-label="Undo"
        >
          <UndoIcon />
        </button>
        <button
          className={`${styles.btn} ${styles.iconBtn}`}
          onClick={handleRedo}
          disabled={!canRedo}
          title="Redo (Ctrl/Cmd+Shift+Z or Ctrl/Cmd+Y)"
          aria-label="Redo"
        >
          <RedoIcon />
        </button>
        <button className={styles.btn} onClick={onSave}>
          {isDirty && <span className={styles.dirtyIndicator} />}
          Save
        </button>
        <button className={styles.btn} onClick={onLoad}>Load</button>
      </div>

      <div className={styles.group}>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'plan' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' })}
          title="Plan View"
        >
          Plan
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_front' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
          title="Front Elevation"
        >
          Front
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_rear' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_rear' })}
          title="Rear Elevation"
        >
          Rear
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_left' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_left' })}
          title="Left Elevation"
        >
          Left
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_right' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_right' })}
          title="Right Elevation"
        >
          Right
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'section_view' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'section_view' })}
          title="Section View"
        >
          Section
        </button>
        <button
          className={`${styles.btn} ${workspaceMode === 'sheet' ? styles.active : ''}`}
          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
          title="Sheet Workspace"
        >
          Sheets
        </button>
      </div>

      <div className={styles.dropdown} ref={toolMenuRef}>
        <button
          className={`${styles.btn} ${styles.dropdownTrigger}`}
          onClick={() => setToolMenuOpen(!toolMenuOpen)}
          disabled={!isPlanView}
        >
          {activeToolLabel}
          <svg viewBox="0 0 10 6" className={styles.chevron} aria-hidden="true">
            <path d="M1 1l4 4 4-4" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </button>
        {toolMenuOpen && (
          <div className={styles.dropdownMenu}>
            {toolItems.map(({ tool, label, shortcut }) => (
              <button
                key={tool}
                className={`${styles.dropdownItem} ${activeTool === tool ? styles.dropdownItemActive : ''}`}
                onClick={() => { setTool(tool); setToolMenuOpen(false); }}
              >
                <span>{label}</span>
                <kbd className={styles.shortcut}>{shortcut}</kbd>
              </button>
            ))}
          </div>
        )}
      </div>

      <div className={styles.group}>
        <button
          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''} ${styles.iconBtn}`}
          onClick={onToggleSidebar}
          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
        >
          <SidebarIcon />
        </button>
        <button
          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''} ${styles.iconBtn}`}
          onClick={onToggleProperties}
          title={isPropertiesCollapsed ? 'Show Properties Panel' : 'Hide Properties Panel'}
          aria-label={isPropertiesCollapsed ? 'Show Properties Panel' : 'Hide Properties Panel'}
        >
          <PropertiesIcon />
        </button>
        <button
          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
          title="Toggle Grid"
        >
          Grid
        </button>
        <button
          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
          title="Toggle Snap"
        >
          Snap
        </button>
        <button
          className={styles.btn}
          onClick={handleDetectRooms}
          title="Auto-detect Rooms"
          disabled={!isPlanView}
        >
          Auto-detect Rooms
        </button>
      </div>

      <div className={styles.spacer} />
    </div>
  );
}

