 82→}) {
 83→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
 84→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 85→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 86→
 87→  const [toolMenuOpen, setToolMenuOpen] = useState(false);
 88→  const toolMenuRef = useRef(null);
 89→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 90→
 91→  const toolItems = [
 92→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V' },
 93→    { tool: TOOLS.DIMENSION, label: 'Dim', shortcut: 'M' },
 94→    { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W' },
 95→    { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B' },
 96→    { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T' },
 97→    { tool: TOOLS.SECTION, label: 'Section', shortcut: 'Q' },
 98→    { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S' },
 99→    { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R' },
100→    { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', hint: 'F to flip swing' },
101→    { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N' },
102→    { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C' },
103→  ];
104→  const activeToolLabel = toolItems.find(t => t.tool === activeTool)?.label || 'Tools';
105→  const handleUndo = useCallback(() => {
106→    if (!canUndo) return;
107→    dispatch({ type: 'UNDO' });
108→    editorDispatch({ type: 'DESELECT' });
109→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
110→  }, [canUndo, dispatch, editorDispatch]);
111→  const handleRedo = useCallback(() => {
112→    if (!canRedo) return;
113→    dispatch({ type: 'REDO' });
114→    editorDispatch({ type: 'DESELECT' });
115→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
116→  }, [canRedo, dispatch, editorDispatch]);
117→
118→  const handleDetectRooms = () => {
119→    const floor = project.floors.find(f => f.id === activeFloorId);
120→    if (!floor || floor.walls.length < 3) {
