138→      if (isTypingTarget(e.target)) return;
139→
140→      const key = e.key.toLowerCase();
141→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
142→      const isUndo = key === 'z' && !e.shiftKey;
143→      if (!isUndo && !isRedo) return;
144→
145→      e.preventDefault();
146→      if (isRedo) {
147→        handleRedo();
148→        return;
149→      }
150→      handleUndo();
151→    };
152→
153→    window.addEventListener('keydown', handleKeyDown);
154→    return () => window.removeEventListener('keydown', handleKeyDown);
155→  }, [handleRedo, handleUndo]);
156→
157→  useEffect(() => {
