178→        >
179→          <UndoIcon />
180→        </button>
181→        <button
182→          className={`${styles.btn} ${styles.iconBtn}`}
183→          onClick={handleRedo}
184→          disabled={!canRedo}
185→          title="Redo (Ctrl/Cmd+Shift+Z or Ctrl/Cmd+Y)"
186→          aria-label="Redo"
187→        >
188→          <RedoIcon />
189→        </button>
190→        <button className={styles.btn} onClick={onSave}>
191→          {isDirty && <span className={styles.dirtyIndicator} />}
192→          Save
193→        </button>
194→        <button className={styles.btn} onClick={onLoad}>Load</button>
195→      </div>
196→
197→      <div className={styles.group}>
198→        <button
199→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'plan' ? styles.active : ''}`}
200→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' })}
201→          title="Plan View"
202→        >
203→          Plan
204→        </button>
205→        <button
206→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_front' ? styles.active : ''}`}
207→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
208→          title="Front Elevation"
209→        >
210→          Front
211→        </button>
212→        <button
213→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_rear' ? styles.active : ''}`}
214→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_rear' })}
215→          title="Rear Elevation"
216→        >
217→          Rear
218→        </button>
219→        <button
220→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_left' ? styles.active : ''}`}
221→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_left' })}
222→          title="Left Elevation"
223→        >
224→          Left
