 1→function pointInRect(point, rect) {
 2→  return (
 3→    point.x >= rect.x
 4→    && point.x <= rect.x + rect.width
 5→    && point.y >= rect.y
 6→    && point.y <= rect.y + rect.height
 7→  );
 8→}
 9→
10→export function getViewportHandleRects(viewport, handleSize) {
11→  const size = handleSize;
12→  return {
13→    nw: { x: viewport.x - size / 2, y: viewport.y - size / 2, width: size, height: size },
14→    ne: { x: viewport.x + viewport.width - size / 2, y: viewport.y - size / 2, width: size, height: size },
15→    sw: { x: viewport.x - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
16→    se: { x: viewport.x + viewport.width - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
17→  };
18→}
19→
20→export function hitTestViewportHandle(point, viewports, handleSize) {
21→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
22→    const viewport = viewports[index];
23→    const handles = getViewportHandleRects(viewport, handleSize);
24→    for (const [key, rect] of Object.entries(handles)) {
25→      if (pointInRect(point, rect)) {
26→        return { viewportId: viewport.id, handle: key };
27→      }
28→    }
29→  }
30→  return null;
31→}
32→
33→export function hitTestViewport(point, viewports) {
34→  for (let index = viewports.length - 1; index >= 0; index -= 1) {
35→    const viewport = viewports[index];
36→    if (pointInRect(point, viewport)) {
37→      return viewport;
38→    }
39→  }
40→  return null;
41→}
