 14→function hitTest(modelPos, floor, annotationTolerance) {
 15→  // Hit test doors first (smaller targets, higher priority)
 16→  for (const door of floor.doors) {
 17→    const wall = floor.walls.find(w => w.id === door.wallId);
 18→    if (!wall) continue;
 19→    const info = doorOutlineOnWall(wall, door);
 20→    const poly = [info.p1, info.p2, info.p3, info.p4];
 21→    if (pointInPolygon(modelPos, poly)) {
 22→      return { id: door.id, type: 'door' };
 23→    }
 24→  }
 25→
 26→  // Hit test windows
 27→  for (const win of floor.windows) {
 28→    const wall = floor.walls.find(w => w.id === win.wallId);
 29→    if (!wall) continue;
 30→    const info = windowOutlineOnWall(wall, win);
 31→    const poly = [info.p1, info.p2, info.p3, info.p4];
 32→    if (pointInPolygon(modelPos, poly)) {
 33→      return { id: win.id, type: 'window' };
 34→    }
 35→  }
 36→
 37→  // Hit test walls
 38→  // Hit test columns
 39→  if (floor.sectionCut && hitTestSectionCut(modelPos, floor.sectionCut, annotationTolerance)) {
 40→    return { id: floor.sectionCut.id, type: 'sectionCut' };
 41→  }
 42→
 43→  for (const column of (floor.columns || [])) {
 44→    const outline = columnOutline(column);
 45→    if (pointInPolygon(modelPos, outline)) {
 46→      return { id: column.id, type: 'column' };
 47→    }
 48→  }
 49→
 50→  // Hit test beams
 51→  for (const beam of (floor.beams || [])) {
 52→    const renderData = getBeamRenderData(beam, floor.columns || []);
 53→    if (!renderData) continue;
 54→    if (pointInPolygon(modelPos, renderData.outline)) {
 55→      return { id: beam.id, type: 'beam' };
 56→    }
 57→  }
 58→
 59→  // Hit test walls
 60→  for (const wall of floor.walls) {
 61→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 62→    if (pointInPolygon(modelPos, outline)) {
 63→      return { id: wall.id, type: 'wall' };
 64→    }
 65→  }
 66→
 67→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 68→  for (const stair of (floor.stairs || [])) {
 69→    const renderData = getStairRenderData(stair);
 70→    if (!renderData) continue;
 71→    if (pointInPolygon(modelPos, renderData.outline)) {
 72→      return { id: stair.id, type: 'stair' };
 73→    }
 74→  }
 75→
 76→  // Hit test rooms (lowest priority)
 77→  for (const room of floor.rooms) {
 78→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 79→      return { id: room.id, type: 'room' };
 80→    }
 81→  }
 82→
 83→  if (floor.slab && slabContainsPoint(floor.slab, modelPos)) {
 84→    return { id: floor.slab.id, type: 'slab' };
 85→  }
 86→
 87→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
 88→  if (annotationHit) {
 89→    return annotationHit;
 90→  }
 91→
 92→  return null;
