100→function AppInner() {
101→  const { project, isDirty, dispatch } = useProject();
102→  const [showLoadModal, setShowLoadModal] = useState(false);
103→  const [savedProjects, setSavedProjects] = useState([]);
104→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
105→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
106→
107→  useAutosave(project, isDirty, dispatch);
108→
109→  // beforeunload warning
110→  useEffect(() => {
111→    const handler = (e) => {
112→      if (isDirty) {
113→        e.preventDefault();
114→        e.returnValue = '';
115→      }
116→    };
117→    window.addEventListener('beforeunload', handler);
118→    return () => window.removeEventListener('beforeunload', handler);
119→  }, [isDirty]);
120→
121→  const handleNew = useCallback(() => {
122→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
123→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
124→  }, [isDirty, dispatch]);
125→
126→  const handleSave = useCallback(async () => {
127→    await saveProject(project);
128→    dispatch({ type: 'MARK_SAVED' });
129→  }, [project, dispatch]);
130→
131→  // Ctrl+S save
132→  useEffect(() => {
