 83→function buildPlanSource(floor) {
 84→  if (!floor) {
 85→    return {
 86→      kind: 'empty',
 87→      title: 'Plan',
 88→      message: 'Missing floor.',
 89→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
 90→    };
 91→  }
 92→
 93→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
 94→
 95→  return {
 96→    kind: 'plan',
 97→    title: `${floor.name} Plan`,
 98→    floor,
 99→    bounds: geometryBounds,
100→  };
101→}
102→
103→function sceneBoundsToRenderBounds(scene) {
104→  return {
105→    minX: scene.bounds.minX - VERTICAL_PADDING,
106→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
107→    minY: -scene.bounds.maxZ - TOP_PADDING,
108→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
109→  };
110→}
111→
112→function buildSectionSource(floor, sourceRefId) {
113→  if (!floor?.sectionCut) {
114→    return {
115→      kind: 'empty',
116→      title: 'Section',
117→      message: 'No section cut on this floor.',
118→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
119→    };
120→  }
121→
122→  if (sourceRefId && floor.sectionCut.id !== sourceRefId) {
123→    return {
124→      kind: 'empty',
125→      title: 'Section',
126→      message: 'Section source not found.',
127→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
128→    };
129→  }
130→
131→  const scene = buildSectionScene(floor);
132→  return {
133→    kind: 'section',
134→    title: floor.sectionCut.label || 'Section',
135→    floor,
136→    scene,
137→    bounds: sceneBoundsToRenderBounds(scene),
138→  };
139→}
140→
141→function buildElevationSource(floor, sourceView) {
142→  if (!floor) {
143→    return {
144→      kind: 'empty',
145→      title: 'Elevation',
146→      message: 'Missing floor.',
147→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
148→    };
149→  }
150→
151→  const scene = buildElevationScene(floor, sourceView);
152→  const annotationScene = buildElevationAnnotationScene(floor, scene);
153→
154→  return {
155→    kind: 'elevation',
156→    title: scene.title,
157→    floor,
158→    viewMode: sourceView,
159→    scene,
160→    annotationScene,
161→    bounds: sceneBoundsToRenderBounds(scene),
162→  };
163→}
164→
165→export function resolveSheetViewportSource(project, viewport) {
166→  const floor = (project.floors || []).find((entry) => entry.id === viewport.sourceFloorId)
167→    || project.floors?.[0]
168→    || null;
169→
170→  switch (viewport.sourceView) {
171→    case 'section':
172→      return buildSectionSource(floor, viewport.sourceRefId);
173→    case 'elevation_front':
