393→      return {
394→        ...state,
395→        project: nextProject,
396→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
397→        future: state.future.slice(1),
398→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
399→      };
400→    }
401→
402→    default:
403→      return state;
404→  }
405→}
406→
407→const initialProject = createProject();
408→
409→const initialState = {
410→  project: initialProject,
411→  isDirty: false,
412→  lastSavedAt: null,
413→  savedSnapshot: snapshotProject(initialProject),
414→  history: [],
415→  future: [],
416→};
417→
418→export function ProjectProvider({ children }) {
419→  const [state, dispatch] = useReducer(projectReducer, initialState);
420→  return (
421→    <ProjectContext.Provider value={{ state, dispatch }}>
422→      {children}
423→    </ProjectContext.Provider>
424→  );
425→}
426→
427→export function useProject() {
428→  const ctx = useContext(ProjectContext);
429→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
430→  const { state, dispatch } = ctx;
431→
432→  return {
433→    project: state.project,
434→    isDirty: state.isDirty,
435→    lastSavedAt: state.lastSavedAt,
436→    canUndo: state.history.length > 0,
437→    canRedo: state.future.length > 0,
438→    dispatch,
439→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
440→  };
441→}
